// HasParentUser applies the HasEdge predicate on the "parent_user" edge.
func HasParentUser() predicate.SubAccount {
	return predicate.SubAccount(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ParentUserTable, ParentUserColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasParentUserWith applies the HasEdge predicate on the "parent_user" edge with a given conditions (other predicates).
func HasParentUserWith(preds ...predicate.User) predicate.SubAccount {
	return predicate.SubAccount(func(s *sql.Selector) {
		step := newParentUserStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

